  public void ApplySquadInfoVisibilityState()
  {
    if (((Control) this.RolesContainer).ChildCount <= 0)
      return;
    for (int index = 0; index < ((Control) this.RolesContainer).ChildCount - 1; ++index)
      ((Control) this.RolesContainer).GetChild(index).Visible = !this._squadInfoHidden;
    if (((Control) this.RolesContainer).ChildCount <= 0)
      return;
    ((Control) this.RolesContainer).GetChild(((Control) this.RolesContainer).ChildCount - 1).Visible = true;
  }

  protected virtual void FrameUpdate(FrameEventArgs args)
  {
    base.FrameUpdate(args);
    this.CrateStatus.Text = this.HasCrate ? "[color=green][bold] \\[ CRATE LOADED \\][/bold][/color]" : "[color=red][bold] \\[ NO CRATE LOADED \\][/bold][/color]";
    TimeSpan curTime = IoCManager.Resolve<IGameTiming>().CurTime;
    TimeSpan timeSpan1 = this.NextLaunchAt - curTime;
    if (timeSpan1 > TimeSpan.Zero)
    {
      this.CrateStatus.Text = $"[color=#D3B400][bold]\\ [ COOLDOWN - {(int) timeSpan1.TotalSeconds} SECONDS \\][/bold][/color]";
      ((BaseButton) this.LaunchButton).Disabled = true;
    }
    else
      ((BaseButton) this.LaunchButton).Disabled = false;
    TimeSpan timeSpan2 = this.NextOrbitalAt - curTime;
    if (timeSpan2 > TimeSpan.Zero)
    {
      this.OrbitalStatus.Text = $"[color=#D3B400][bold]\\ [ COOLDOWN - {(int) timeSpan2.TotalSeconds} SECONDS \\][/bold][/color]";
      ((BaseButton) this.OrbitalFireButton).Disabled = true;
    }
    else
    {
      this.OrbitalStatus.Text = this.HasOrbital ? "[color=green][bold] \\[ READY \\][/bold][/color]" : "[color=red][bold] \\[ NOT READY \\][/bold][/color]";
      ((BaseButton) this.OrbitalFireButton).Disabled = false;
    }
  }

